# Simple file backup checker example
import os
import time

def check_backup_age(backup_path):
    if os.path.exists(backup_path):
        age_days = (time.time() - os.path.getmtime(backup_path)) / 86400
        if age_days > 7:
            print("WARNING: Backup older than 7 days")
        else:
            print("Backup is recent and valid")
    else:
        print("ERROR: No backup found!")

# Run backup check
check_backup_age("/backups/important_data.zip")
